from flask import Flask, jsonify, request
from pymongo import MongoClient
import json

app = Flask(__name__)

# Connect to MongoDB
client = MongoClient('localhost', 27017)
db = client['cms']

# Define a collection for user profiles
profiles_collection = db['user_profiles']
documents_collection = db['documents']

# Function to retrieve user profile by id
def get_user_profile(user_id):
    return profiles_collection.find_one({'_id': user_id})

# Function to store document in MongoDB
def store_document(title, content, user_id):
    documents_collection.insert_one({
        'title': title,
        'content': content,
        'user_id': user_id
    })

# Function to retrieve all documents for a given user
def get_user_documents(user_id):
    return list(documents_collection.find({'user_id': user_id}))

# Function to create an aggregation pipeline
def create_aggregation_pipeline():
    pipeline = [
        {
            '$match': {'user_id': request.args.get('user_id')}
        },
        {
            '$sort': {'title': 1}
        }
    ]
    return pipeline

# Route to retrieve all documents for a given user
@app.route('/documents', methods=['GET'])
def get_user_documents_route():
    user_id = request.args.get('user_id')
    documents = get_user_documents(user_id)
    return jsonify(documents)

# Route to create an aggregation pipeline and execute it
@app.route('/aggregate', methods=['GET'])
def aggregate_documents_route():
    pipeline = create_aggregation_pipeline()
    result = list(documents_collection.aggregate(pipeline))
    return jsonify(result)

if __name__ == '__main__':
    app.run(debug=True)